import { Player, Position, StoredPlayerTier } from "../types";
import { getTierFromOverall } from "../lib/playerTier";
import { normalizePlayerSeedRatings } from "../lib/playerRatings";

interface PlayerSeed {
  name: string;
  era: string;
  teamLabel: string;
  primaryPosition: Position;
  secondaryPositions: Position[];
  overall: number;
  offense: number;
  defense: number;
  playmaking: number;
  shooting: number;
  rebounding: number;
  athleticism: number;
  intangibles: number;
  durability: number;
  archetype: string;
  hallOfFameTier: StoredPlayerTier;
  shortDescription: string;
  badges: string[];
  ballDominance: number;
  interiorDefense: number;
  perimeterDefense: number;
}

const toPlayerId = (name: string) => name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");

const dedupePositions = (positions: Position[]) =>
  positions.filter((position, index) => positions.indexOf(position) === index);

