const inferCurrentSeasonSecondaryPositions = (seed: PlayerSeed): Position[] => {
  const override = currentSeasonPositionOverrides[toPlayerId(seed.name)];
  if (override) return dedupePositions(override.filter((position) => position !== seed.primaryPosition));

  const positions: Position[] = [];
  const hasBadge = (badge: string) => seed.badges.includes(badge);

  switch (seed.primaryPosition) {
    case "PG":
      positions.push("SG");
      if (
        seed.rebounding >= 86 ||
        seed.interiorDefense >= 80 ||
        seed.perimeterDefense >= 88 ||
        hasBadge("Wing Stopper") ||
        hasBadge("Glass Cleaner")
      ) {
        positions.push("SF");
      }
      break;
    case "SG":
      if (
        seed.playmaking >= 86 ||
        seed.ballDominance >= 78 ||
        seed.archetype.includes("Offensive Engine") ||
        seed.archetype.includes("Connector Creator") ||
        seed.archetype.includes("Shotmaking Guard")
      ) {
        positions.push("PG");
      }
      if (
        seed.rebounding >= 82 ||
        seed.interiorDefense >= 77 ||
        seed.perimeterDefense >= 84 ||
        hasBadge("Wing Stopper")
      ) {
        positions.push("SF");
      }
      break;
    case "SF":
      if (
        seed.rebounding >= 84 ||
        seed.interiorDefense >= 83 ||
        hasBadge("Glass Cleaner") ||
        hasBadge("Switchable Big")
      ) {
        positions.push("PF");
      }
      if (
        seed.playmaking >= 84 ||
        seed.ballDominance >= 75 ||
        seed.archetype.includes("Connector Creator") ||
        seed.archetype.includes("Perimeter Sniper")
      ) {
        positions.push("SG");
      }
      if (seed.playmaking >= 88 && seed.ballDominance >= 82) {
        positions.push("PG");
      }
      break;
    case "PF":
      if (
        seed.rebounding >= 85 ||
        seed.interiorDefense >= 84 ||
        seed.archetype.includes("Interior") ||
        hasBadge("Rim Protector")
      ) {
        positions.push("C");
      }
      if (
        seed.perimeterDefense >= 82 ||
        seed.playmaking >= 80 ||
        seed.shooting >= 84 ||
        seed.archetype.includes("Floor Spacer")
      ) {
        positions.push("SF");
      }
      break;
    case "C":
      positions.push("PF");
      break;
  }

  const fallbackByPrimary: Record<Position, Position> = {
    PG: "SG",
    SG: "SF",
    SF: "PF",
    PF: "C",
    C: "PF",
  };

  if (positions.length === 0) positions.push(fallbackByPrimary[seed.primaryPosition]);
  return dedupePositions(positions.filter((position) => position !== seed.primaryPosition));
};

const makePlayer = (seed: PlayerSeed): Player => {
  const secondaryPositions =
    seed.secondaryPositions.length > 0 ? dedupePositions(seed.secondaryPositions) : inferCurrentSeasonSecondaryPositions(seed);
  const normalizedRatings = normalizePlayerSeedRatings({
    ...seed,
    secondaryPositions,
  });

  return {
    id: toPlayerId(seed.name),
    ...seed,
    ...normalizedRatings,
    hallOfFameTier: getTierFromOverall(seed.overall),
    secondaryPositions,
  };
};

